func messagePreview(body string) string {
	trimmed := strings.TrimSpace(body)
	if trimmed == "" {
		return ""
	}
	preview := strings.Join(strings.Fields(trimmed), " ")
	runes := []rune(preview)
	if len(runes) <= 88 {
		return preview
	}
	return string(runes[:88]) + "..."
}

